import{_ as a,o,c as i,ag as s}from"./chunks/framework.ByAj6Cie.js";const m=JSON.parse('{"title":"Industrial Systems Handbook","description":"","frontmatter":{},"headers":[],"relativePath":"es/home/overview.md","filePath":"es/home/overview.md"}'),r={name:"es/home/overview.md"};function n(t,e,l,c,d,u){return o(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="industrial-systems-handbook" tabindex="-1">Industrial Systems Handbook <a class="header-anchor" href="#industrial-systems-handbook" aria-label="Permalink to &quot;Industrial Systems Handbook&quot;">​</a></h1><p>Una guía práctica para entender, diseñar y seleccionar sistemas industriales — sin complejidad innecesaria.</p><hr><h2 id="¿que-es-esto" tabindex="-1">¿Qué es esto? <a class="header-anchor" href="#¿que-es-esto" aria-label="Permalink to &quot;¿Qué es esto?&quot;">​</a></h2><p>Industrial Systems Handbook es una colección curada de conceptos, componentes y conocimiento práctico utilizados en entornos industriales.</p><p>No está diseñado para reemplazar hojas de datos, normas o diseño de ingeniería detallado.</p><p>En cambio, te ayuda a:</p><ul><li>Entender <strong>qué son las cosas</strong></li><li>Aprender <strong>cómo funcionan</strong></li><li>Saber <strong>cuándo y por qué utilizarlas</strong></li></ul><hr><h2 id="¿por-que-existe" tabindex="-1">¿Por qué existe? <a class="header-anchor" href="#¿por-que-existe" aria-label="Permalink to &quot;¿Por qué existe?&quot;">​</a></h2><p>En la ingeniería del mundo real, las personas rara vez comienzan desde la teoría.</p><p>Empiezan con preguntas como:</p><ul><li><em>¿Qué cable debería usar?</em></li><li><em>¿Cuál es la diferencia entre este PLC y aquel?</em></li><li><em>¿Por qué está fallando este sistema?</em></li></ul><p>El problema es que la mayoría de los recursos son:</p><ul><li>Demasiado <strong>básicos</strong> (no útiles en la práctica), o</li><li>Demasiado <strong>complejos</strong> (difíciles de aplicar rápidamente)</li></ul><p>Este proyecto existe para cerrar esa brecha.</p><hr><h2 id="¿para-quien-es" tabindex="-1">¿Para quién es? <a class="header-anchor" href="#¿para-quien-es" aria-label="Permalink to &quot;¿Para quién es?&quot;">​</a></h2><ul><li>Estudiantes que están aprendiendo sistemas industriales</li><li>Ingenieros que inician o hacen transición hacia la industria</li><li>Técnicos que trabajan con equipos reales</li><li>Cualquier persona que quiera entender cómo funcionan realmente los sistemas</li></ul><hr><h2 id="¿como-usar-este-sitio" tabindex="-1">¿Cómo usar este sitio? <a class="header-anchor" href="#¿como-usar-este-sitio" aria-label="Permalink to &quot;¿Cómo usar este sitio?&quot;">​</a></h2><p>No necesitas leer todo en orden.</p><p>Puedes:</p><ul><li>Empezar desde fundamentos (recomendado si eres nuevo)</li><li>Ir directamente a un tema (cables, PLCs, motores, etc.)</li><li>Usarlo como referencia cuando algo no esté claro</li></ul><hr><h2 id="¿que-encontraras" tabindex="-1">¿Qué encontrarás? <a class="header-anchor" href="#¿que-encontraras" aria-label="Permalink to &quot;¿Qué encontrarás?&quot;">​</a></h2><ul><li>Fundamentos eléctricos</li><li>Sistemas de potencia y protección</li><li>Cables y prácticas de instalación</li><li>Equipos industriales (motores, variadores, sensores, actuadores)</li><li>Sistemas de control (PLC, HMI, SCADA)</li><li>Instrumentación y señales</li><li>Redes industriales</li><li>Decisiones prácticas de ingeniería</li></ul><hr><h2 id="¿que-no-encontraras" tabindex="-1">¿Qué NO encontrarás? <a class="header-anchor" href="#¿que-no-encontraras" aria-label="Permalink to &quot;¿Qué NO encontrarás?&quot;">​</a></h2><ul><li>Sesgo hacia marcas específicas</li><li>Explicaciones excesivamente académicas</li><li>Complejidad innecesaria</li></ul><p>Cuando se requiera mayor profundidad, aún necesitarás:</p><ul><li>Hojas de datos</li><li>Normas</li><li>Documentación de fabricantes</li></ul><hr><h2 id="filosofia" tabindex="-1">Filosofía <a class="header-anchor" href="#filosofia" aria-label="Permalink to &quot;Filosofía&quot;">​</a></h2><p>Esto no se trata de saberlo todo.</p><p>Se trata de entender lo suficiente para:</p><ul><li>Tomar mejores decisiones</li><li>Hacer mejores preguntas</li><li>Aprender más rápido en entornos reales</li></ul><hr><h2 id="estado-del-proyecto" tabindex="-1">Estado del proyecto <a class="header-anchor" href="#estado-del-proyecto" aria-label="Permalink to &quot;Estado del proyecto&quot;">​</a></h2><p>Este es un proyecto en evolución.</p><p>Algunas secciones están completas, otras aún están en desarrollo.<br> Puedes revisar el progreso en el roadmap.</p><hr><h2 id="apoya-y-contribuye" tabindex="-1">Apoya y contribuye <a class="header-anchor" href="#apoya-y-contribuye" aria-label="Permalink to &quot;Apoya y contribuye&quot;">​</a></h2><p>Si este proyecto te resulta útil:</p><ul><li>Puedes apoyarlo (donaciones)</li><li>Puedes contribuir a través de GitHub</li></ul><p>Más información:</p><ul><li><code>/home/support</code></li><li><code>/home/contribute</code></li></ul>',47)])])}const h=a(r,[["render",n]]);export{m as __pageData,h as default};
